import React, { useEffect, useState, useRef } from 'react';
import { useParams, useLocation, Link } from 'react-router-dom';
import { Project } from '../types';

const getVimeoEmbedUrl = (link?: string) => {
  if (!link) return '';
  try {
    const url = new URL(link);
    if (url.hostname.includes('player.vimeo.com')) {
      const h = url.searchParams.get('h');
      return h ? `${url.origin}${url.pathname}?h=${h}` : `${url.origin}${url.pathname}`;
    }
  } catch (e) {}
  const m = String(link).match(/vimeo\.com\/(?:.*\/)?(\d+)(?:\/([0-9A-Za-z_-]+))?/)
    || String(link).match(/player\.vimeo\.com\/video\/(\d+)(?:\?h=([0-9A-Za-z_-]+))?/);
  if (!m) return link;
  const id = m[1];
  const hash = m[2];
  return hash ? `https://player.vimeo.com/video/${id}?h=${hash}` : `https://player.vimeo.com/video/${id}`;
};

type LocationState = { project?: Project };

const VideoWrapper: React.FC<{ src?: string; title?: string; autoplay?: boolean }> = ({ src, title, autoplay = true }) => {
  const iframeRef = useRef<HTMLIFrameElement | null>(null);
  const playerRef = useRef<any>(null);
  const lastVolumeRef = useRef<number>(1);
  const [isPlaying, setIsPlaying] = useState<boolean>(false);
  const [duration, setDuration] = useState<number>(0);
  const [time, setTime] = useState<number>(0);
  const [muted, setMuted] = useState<boolean>(true);

  useEffect(() => {
    if (!src || !iframeRef.current) return;
    let mounted = true;
    let Player: any;
    (async () => {
      try {
        const mod = await import('@vimeo/player');
        Player = mod.default ?? (mod as any).Player;
        playerRef.current = new Player(iframeRef.current, {
          url: src,
          autoplay: autoplay,
          controls: false,   // remove Vimeo native controls
          playsinline: true,
        });

        // capture initial volume, then mute for autoplay if requested
        try {
          const vol = await playerRef.current.getVolume();
          lastVolumeRef.current = vol ?? 1;
        } catch (e) {
          lastVolumeRef.current = 1;
        }

        if (autoplay) {
          // set volume to 0 to ensure autoplay in browsers, mark muted
          try { await playerRef.current.setVolume(0); } catch (e) {}
          setMuted(true);
          try { await playerRef.current.play(); } catch (e) { /* autoplay blocked */ }
        } else {
          setMuted((await playerRef.current.getVolume()) === 0);
        }

        playerRef.current.on('play', () => { if (mounted) setIsPlaying(true); });
        playerRef.current.on('pause', () => { if (mounted) setIsPlaying(false); });
        playerRef.current.getDuration().then((d: number) => { if (mounted) setDuration(d); });
        playerRef.current.on('timeupdate', (data: any) => { if (mounted) setTime(data.seconds); });
      } catch (err) {
        // fallback: set iframe src with autoplay & muted params and hide controls
        if (iframeRef.current && !iframeRef.current.src) {
          const sep = src.includes('?') ? '&' : '?';
          iframeRef.current.src = `${src}${sep}autoplay=${autoplay ? '1' : '0'}&muted=1&playsinline=1&controls=0`;
          setMuted(true);
        }
      }
    })();

    return () => {
      mounted = false;
      if (playerRef.current && typeof playerRef.current.unload === 'function') {
        playerRef.current.unload().catch(() => {});
      }
      playerRef.current = null;
    };
  }, [src, autoplay]);

  const togglePlay = async () => {
    if (!playerRef.current) return;
    try {
      if (isPlaying) await playerRef.current.pause();
      else await playerRef.current.play();
    } catch (e) {}
  };

  const toggleMute = async () => {
    if (!playerRef.current) {
      // fallback: toggle iframe src params not possible ŌĆö no-op
      return;
    }
    try {
      if (muted) {
        // restore last known volume (or 1)
        const vol = lastVolumeRef.current || 1;
        await playerRef.current.setVolume(vol);
        setMuted(false);
      } else {
        // remember current volume then mute
        try {
          const current = await playerRef.current.getVolume();
          lastVolumeRef.current = current ?? lastVolumeRef.current;
        } catch (e) {}
        await playerRef.current.setVolume(0);
        setMuted(true);
      }
    } catch (e) {}
  };

  const seek = async (ev: React.ChangeEvent<HTMLInputElement>) => {
    if (!playerRef.current) return;
    const pct = Number(ev.target.value);
    const t = (pct / 100) * (duration || 0);
    try { await playerRef.current.setCurrentTime(t); } catch (e) {}
  };

  return (
    <div style={{ width: '80%', maxWidth: 1200, margin: '0 auto 1.25rem' }}>
      <div style={{ position: 'relative', paddingTop: '56.25%', background: '#111', overflow: 'hidden' }}>
        <iframe
          ref={iframeRef}
          title={title || 'Project video'}
          frameBorder="0"
          allow="autoplay; fullscreen; picture-in-picture"
          allowFullScreen
          style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}
        />
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginTop: 10 }}>
        <button
          onClick={togglePlay}
          aria-label={isPlaying ? 'Pause' : 'Play'}
          style={{
            background: 'transparent',
            border: '1px solid rgba(255,255,255,0.12)',
            color: '#EDEDED',
            padding: '6px 10px',
            cursor: 'pointer',
            fontFamily: 'IBM Plex Mono, monospace',
            textTransform: 'uppercase',
            fontSize: 12,
            letterSpacing: '0.12em'
          }}
        >
          {isPlaying ? 'Pause' : 'Play'}
        </button>

        <button
          onClick={toggleMute}
          aria-label={muted ? 'Unmute' : 'Mute'}
          style={{
            background: 'transparent',
            border: '1px solid rgba(255,255,255,0.12)',
            color: '#EDEDED',
            padding: '6px 10px',
            cursor: 'pointer',
            fontFamily: 'IBM Plex Mono, monospace',
            textTransform: 'uppercase',
            fontSize: 12,
            letterSpacing: '0.12em'
          }}
        >
          {muted ? 'Unmute' : 'Mute'}
        </button>

        <input
          type="range"
          min={0}
          max={100}
          value={duration ? Math.min(100, Math.round((time / duration) * 100)) : 0}
          onChange={seek}
          style={{ flex: 1 }}
        />

        <div style={{ color: '#bdbdbd', fontSize: 12, fontFamily: 'IBM Plex Mono, monospace' }}>
          {duration ? `${Math.floor(time)}/${Math.floor(duration)}s` : '--/--'}
        </div>
      </div>
    </div>
  );
};

const ProjectDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation<LocationState>();
  const [project, setProject] = useState<Project | null>(location.state?.project ?? null);
  const [loading, setLoading] = useState<boolean>(!project);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (project) return;
    let mounted = true;
    setLoading(true);

    (async () => {
      try {
        const res = await fetch(`/api/projects/${id}`);
        if (!res.ok) throw new Error('Network response was not ok');
        const raw = await res.json();
        const normalized: Project = {
          ...raw,
          createdAt: raw.createdAt ? new Date(raw.createdAt) : raw.createdAt,
          updatedAt: raw.updatedAt ? new Date(raw.updatedAt) : raw.updatedAt,
          videoUrl: raw.videoUrl ?? raw.originalVideoLink ?? raw.link ?? raw.videoUrl,
          link: raw.link ?? raw.videoUrl ?? raw.originalVideoLink ?? raw.link,
        };
        if (mounted) setProject(normalized);
      } catch (err) {
        if (mounted) setError('Failed to load project.');
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => { mounted = false; };
  }, [id, project]);

  if (loading) return <div style={{ padding: 40 }}>LoadingŌĆ”</div>;
  if (error) return <div style={{ padding: 40 }}>{error}</div>;
  if (!project) return <div style={{ padding: 40 }}>Project not found.</div>;

  const videoSrcRaw = (project as any).videoUrl || (project as any).originalVideoLink || (project as any).link || '';
  const videoSrc = getVimeoEmbedUrl(videoSrcRaw);

  return (
    <main style={{ padding: '3rem 4rem', textAlign: 'center' }}>
      <Link to="/" style={{ display: 'inline-block', marginBottom: '1rem', color: '#EDEDED', textDecoration: 'none' }}>
        ŌåÉ Back
      </Link>

      <VideoWrapper src={videoSrc || (project.thumbnail ?? '')} title={project.title} autoplay />

      <div style={{ maxWidth: 900, margin: '0 auto', textAlign: 'center', color: '#ddd' }}>
        {project.description ? <p style={{ marginTop: 12, lineHeight: 1.6 }}>{project.description}</p> : null}
      </div>

      <section style={{ marginTop: 28 }}>

        <h1 style={{ fontFamily: 'Playfair Display, serif', color: '#EDEDED', margin: '0 0 1rem 0' }}>
        {project.title}
      </h1>

      <div style={{ color: '#bdbdbd', textTransform: 'uppercase', letterSpacing: '0.12em', fontSize: '0.85rem', marginBottom: '1.5rem' }}>
        {project.category ?? 'All Projects'}{project.role ? ` ŌĆö ${project.role}` : ''}
      </div>

        <h3 style={{ fontSize: '0.85rem', textTransform: 'uppercase', letterSpacing: '0.12em', color: '#bdbdbd', marginBottom: '0.75rem' }}>
          Additional Material
        </h3>

        {Array.isArray((project as any).assets) && (project as any).assets.length > 0 ? (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '0.75rem' }}>
            {(project as any).assets.map((a: any, i: number) => (
              <div key={i} style={{ background: '#111', padding: 8 }}>
                {a.type === 'video' ? (
                  <iframe
                    src={getVimeoEmbedUrl(a.src)}
                    title={`asset-${i}`}
                    frameBorder="0"
                    allow="autoplay; fullscreen; picture-in-picture"
                    allowFullScreen
                    style={{ width: '100%', height: 120 }}
                  />
                ) : (
                  <img src={a.src} alt={a.label || `asset-${i}`} style={{ width: '100%', height: 120, objectFit: 'cover' }} />
                )}
              </div>
            ))}
          </div>
        ) : (
          <div style={{ color: '#8f8f8f' }}>No extra assets. Add photos / bts / other videos in the admin panel.</div>
        )}
      </section>
    </main>
  );
};

export default ProjectDetail;
